<template><div class="grid"><section class="galaxy-card span5"><h3 class="section-title">上传音频并训练声音</h3><el-form label-position="top" class="form-grid"><el-form-item label="声音名称"><el-input v-model="form.name" placeholder="如：我的带货声线" /></el-form-item><el-form-item label="声音描述"><el-input v-model="form.description" type="textarea" placeholder="描述适用场景" /></el-form-item><el-form-item label="音频文件"><el-upload drag :auto-upload="false" :limit="1" :on-change="f=>file=f.raw"><el-icon size="42"><UploadFilled /></el-icon><div>拖拽或点击上传 wav/mp3/webm</div></el-upload></el-form-item><div class="audio-preview"><div class="page-title"><b>浏览器录音</b><el-tag type="info">MediaRecorder</el-tag></div><div class="muted">录制清晰人声样本，用于声音训练流程。</div><div style="margin-top:12px"><el-button :type="recording?'danger':'primary'" @click="toggleRecord">{{recording?'停止录音':'开始录音'}}</el-button><audio v-if="recordUrl" :src="recordUrl" controls style="width:100%;margin-top:12px"></audio></div></div><el-button type="primary" size="large" :loading="loading" @click="train">提交训练</el-button></el-form></section><section class="galaxy-card span7"><div class="page-title"><h3 class="section-title">声音库管理</h3><el-button @click="load">刷新</el-button></div><table class="neon-table"><thead><tr><th>名称</th><th>说明</th><th>状态</th><th>创建时间</th><th>操作</th></tr></thead><tbody><tr v-for="v in voices" :key="v.id"><td>{{v.name}}</td><td>{{v.description}}</td><td><span :class="['status',v.status==='就绪'?'ready':v.status==='失败'?'fail':'']">{{v.status}}</span></td><td>{{v.created_at||v.createdAt}}</td><td><el-button link @click="$router.push('/tts')">使用</el-button><el-popconfirm title="确认删除？" @confirm="remove(v.id)"><template #reference><el-button link type="danger">删除</el-button></template></el-popconfirm></td></tr></tbody></table></section></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getVoiceList, uploadAudio, startVoiceTrain, createVoice, deleteVoice } from '@/api/voice';const voices=ref([]),file=ref(null),recording=ref(false),recordBlob=ref(null),recordUrl=ref(''),media=ref(null),loading=ref(false);const form=reactive({name:'',description:''});async function load(){voices.value=await getVoiceList()}onMounted(load);async function toggleRecord(){if(!navigator.mediaDevices)return ElMessage.warning('当前浏览器不支持录音');if(!recording.value){const stream=await navigator.mediaDevices.getUserMedia({audio:true});media.value=new MediaRecorder(stream);const chunks=[];media.value.ondataavailable=e=>chunks.push(e.data);media.value.onstop=()=>{recordBlob.value=new Blob(chunks,{type:'audio/webm'});recordUrl.value=URL.createObjectURL(recordBlob.value);stream.getTracks().forEach(t=>t.stop())};media.value.start();recording.value=true}else{media.value.stop();recording.value=false}}async function train(){if(!form.name)return ElMessage.warning('请填写声音名称');if(!file.value&&!recordBlob.value)return ElMessage.warning('请上传或录制音频');loading.value=true;try{const fd=new FormData();fd.append('file',file.value||recordBlob.value,file.value?.name||'record.webm');const up=await uploadAudio(fd);const filePath=up.filePath||up.file_path||up.audioFilePath||up.url;let voice;try{voice=await createVoice({...form,audio_file_path:filePath,audioFilePath:filePath,status:'训练中'})}catch{voice={id:Date.now()}}await startVoiceTrain({voiceModelId:voice.id||voice.voiceModelId,voice_model_id:voice.id||voice.voiceModelId,audioFilePath:filePath,audio_file_path:filePath});ElMessage.success('已提交训练任务');Object.assign(form,{name:'',description:''});file.value=null;recordBlob.value=null;recordUrl.value='';load()}finally{loading.value=false}}async function remove(id){await deleteVoice(id);ElMessage.success('已删除');load()}</script>
